import{_ as e}from"./chunks/add_icon.D_Q72d6b.js";import{_ as d,c,o as a,aj as t}from"./chunks/framework.CjkNaYQl.js";const u=JSON.parse('{"title":"2. 軟體精熟篇","description":"","frontmatter":{},"headers":[],"relativePath":"intermediate/2.md","filePath":"intermediate/2.md"}'),i={name:"intermediate/2.md"};function l(s,o,n,r,p,h){return a(),c("div",null,[...o[0]||(o[0]=[t('<h1 id="_2-軟體精熟篇" tabindex="-1">2. 軟體精熟篇 <a class="header-anchor" href="#_2-軟體精熟篇" aria-label="Permalink to &quot;2. 軟體精熟篇&quot;">​</a></h1><p>相信大家藉由基階課程中都已經學到軟體的基本操作方式了，因此在這篇中階教材中，我們將會以更快的速度來說明更多比賽必備的操作，要是能把這些東西都玩熟，一定能在初賽中取得好成績！</p><h2 id="變數" tabindex="-1">變數 <a class="header-anchor" href="#變數" aria-label="Permalink to &quot;變數&quot;">​</a></h2><p>要在專案中建立變數，要先到畫面上方 <code>管理員</code> → <code>變數</code> 來開啟變數管理的頁面，要注意，我們所有建立的變數都只會用到 <code>專案變數</code>，小心不要建立到 <code>全域變數</code> 而造成命名污染。</p><p>我們在 <code>專案變數</code> → <code>變數</code> 畫面，就可以建立一個變數了，變數型別有很多，可以在 <code>型別</code> 的下拉選單中，選擇一種資料類型，相信這些東西對於會寫程式的人來說再熟悉不過了，但若沒學過程式的人也不要緊張，我們在大多數情況下，變數都只是為了計數，因此直接選擇 <code>int</code>（整數）即可。<code>名稱</code> 同樣也要遵守稱式中變數命名規則，即只用<strong>英文、數字、底線</strong>，且不能有空格。最後的 <code>值</code> 實際上是選填的，若空著不填，它預設就會是 <code>0</code>（在 <code>int</code> 時），因此若是為了計數，不用特別去輸入任何數值。打完這些後，記得點擊 <code>新增</code> 按鈕，才算建立好變數，建立好後即可關閉變數管理頁面。</p><h2 id="display" tabindex="-1">Display <a class="header-anchor" href="#display" aria-label="Permalink to &quot;Display&quot;">​</a></h2><p>顧名思義，<code>Display</code> 節點就是用來顯示資訊的，有點類似傳統程式語言中的輸出函式。</p><p>這個節點可以設定的東西都很直觀，<code>文字顏色</code> 和 <code>背景顏色</code> 的設定應該不用多說，比賽時若會用到 <code>Display</code>，也不會特別要求這部分。<code>標題</code> 和 <code>內文</code> 的輸入格式就比較特別了，一般的文字要使用 <code>&quot;</code> 來包住，並且在連接變數時，會使用 <code>+</code>；輸入變數或特殊功能文字（如<strong>換行</strong>使用的 <code>newline</code>）則可以使用 <code>內文</code> 旁的鉛筆符號來插入；而連接這些元素的，則是使用 <code>+</code>。</p><p>舉個例子，若我想要輸出變數 <code>a</code>、<code>b</code>、<code>c</code> 的值，並成三行，我就可以把 <code>內文</code> 寫成：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;a: &quot; + var_a + newline + &quot;b: &quot; + var_b + newline + &quot;c: &quot; + var_c</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">小提示</p><p>雖然 <code>Display</code> 設定起來自由度很高，不過通常比賽中也只會要求諸如「輸出某個資訊」等，不必過於拘泥形式。</p></div><h2 id="set-變數" tabindex="-1">Set（變數） <a class="header-anchor" href="#set-變數" aria-label="Permalink to &quot;Set（變數）&quot;">​</a></h2><p>前面我們已經學過利用 <code>Set</code> 節點來控制夾爪的開閉了，這章我們就來說如何利用 <code>Set</code> 來控制變數。</p><p>在 <code>Set</code> 編輯畫面中，點擊 <code>變數</code> 右邊的 <code>選擇</code>，並點擊右邊跳出來的變數設定視窗上方 <img src="'+e+'" alt="新增變數控制圖示" style="width:25px;display:inline;vertical-align:middle;margin:0 5px;">，它會跳出一個新的 <code>運算式編輯器</code> 視窗，選擇左側 <code>變數</code> 類別，就可以利用 <code>插入</code> 鍵將變數插入右側輸入框中。</p><p>右側分成了三個框框，分別是上方<strong>被操作值</strong>、中間<strong>運算子</strong>、下方<strong>操作值</strong>，它們三個共同組成一個表達式，如同程式中變數控制那般。舉個例子，若我想要把變數 <code>a</code> 設為 <code>0</code>，我就可以在上方插入 <code>var_a</code>、中間選擇 <code>=</code>、下方輸入 <code>0</code>；或者我想把變數 <code>a</code> 加一，就可以在上方插入 <code>var_a</code>、中間選擇 <code>+=</code>、下方輸入 <code>1</code>。</p><p>操作完成後，記得點擊 <code>確定</code> 以儲存操作，就完成了變數控制的操作，可以關閉 <code>Set</code> 設定視窗了。</p><div class="tip custom-block"><p class="custom-block-title">小提示</p><p>其實在 <code>常數</code>、<code>函式</code>、<code>數學</code> 類別中，也提供了許多內建好用的值或函數可供使用，有空可以自己玩玩看。此篇教材將不會特別介紹它。</p><p>另外，其實 <code>Set</code> 也可以同時控制好幾件事，例如同時控制兩個變數，或者同時控制變數和末端模組等，只需要用 <img src="'+e+'" alt="新增變數控制圖示" style="width:25px;display:inline;vertical-align:middle;margin:0 5px;"> 建立一個以上的設定，就可以只用一個 <code>Set</code> 同時控制不止一個行為。</p></div><h2 id="if" tabindex="-1">If <a class="header-anchor" href="#if" aria-label="Permalink to &quot;If&quot;">​</a></h2><p>在學會了建立和控制變數後，接下來我們還得要讓機器因應不同變數狀態去執行不同任務，而為了讓機器判斷變數狀態，就得用到 <code>If</code>。</p><p><code>If</code> 的設定方式和用 <code>Set</code> 控制變數的流程其實有一定相似度，開啟 <code>If</code> 編輯畫面，點擊 <code>變數</code> 右邊的 <code>選擇</code>，並點擊右邊跳出來的變數設定視窗上方 <img src="'+e+'" alt="新增變數控制圖示" style="width:25px;display:inline;vertical-align:middle;margin:0 5px;">，它會跳出一個新的 <code>運算式編輯器</code> 視窗，和 <code>Set</code> 的設定視窗極為相似，選擇左側 <code>變數</code> 類別，就可以利用 <code>插入</code> 鍵將變數插入右側輸入框中。</p><p>右側分成了三個框框，分別是上方<strong>被判斷值</strong>、中間<strong>運算子</strong>、下方<strong>判斷值</strong>，它們三個共同組成一個表達式，如同程式中判斷變數的方式。舉個例子，若我想看變數 <code>a</code> 是不是不等於 <code>5</code>，就可以在上方插入 <code>var_a</code>、中間選擇 <code>!=</code>、下方輸入 <code>5</code>。</p><div class="tip custom-block"><p class="custom-block-title">小提示</p><p>其實 <code>If</code> 節點不止可以判斷變數，也可以判斷末端模組狀態等等，這些都可以自己研究看看，決賽有機會會用到。此篇教材將不會特別介紹它，但若不會操作，可以至<a href="/YMSH_TMRobot_Textbook/home/guide.html">網站說明</a>找我的聯繫方式來詢問。</p><p>另外，其實 <code>If</code> 也可以同時判斷好幾件事，例如同時判斷兩個變數，或者同時判斷變數和末端模組狀態等，只需要用 <img src="'+e+'" alt="新增變數控制圖示" style="width:25px;display:inline;vertical-align:middle;margin:0 5px;"> 建立一個以上的設定，並在 <code>變數判斷規則</code> 中選擇 <code>或</code> 或 <code>且</code>，就可以只用一個 <code>If</code> 同時判斷不止一件事。</p></div><h2 id="gateway" tabindex="-1">Gateway <a class="header-anchor" href="#gateway" aria-label="Permalink to &quot;Gateway&quot;">​</a></h2><p><code>Gateway</code> 的設定方式與 <code>If</code> 極為相似，但在設定 <code>Gateway</code> 時，可以一次設定數個不同分支，有點像 C 語言的 switch-case 或 Python 的 match-case 語法。</p><p>要設定 <code>Gateway</code>，我們可以點擊 <code>Gateway</code> 節點的鉛筆按鈕，打開它的編輯視窗，再點擊 <img src="'+e+'" alt="新增條件設定圖示" style="width:25px;display:inline;vertical-align:middle;margin:0 5px;"> 來新增條件，存在的條件會顯示在下方，可以透過它個各自的鉛筆圖示來設定不同條件，全部設定完後，即可完成 <code>Gateway</code> 的設定。</p><h2 id="wait-for-變數" tabindex="-1">Wait for（變數） <a class="header-anchor" href="#wait-for-變數" aria-label="Permalink to &quot;Wait for（變數）&quot;">​</a></h2><p><code>Wait for</code> 除了等待「時間」外，也可以用類似 <code>If</code> 的表達式來等到某條件達成後再繼續，不過通常這會配合其他硬體設備的狀態，比較不常用來判斷變數，故此章不詳細展開。</p><h2 id="pallet" tabindex="-1">Pallet <a class="header-anchor" href="#pallet" aria-label="Permalink to &quot;Pallet&quot;">​</a></h2><p>大家在自己玩手臂時，不知道有沒有試過想要把那塊放麻將的小板子放滿呢？但你會發現，如果要達成這件事，在只用 <code>Point</code> 的情況下非常麻煩，而此時，本章介紹的 <code>Pallet</code> 就能派上用場了！</p><p><code>Pallet</code> 可以讓使用者只需要對好三個位置，它就能夠依比例自動計算出一個長方形各點的坐標，對於放麻將的小板子而言，要設的點從原來的六個減少為了三個，還不需要手動控制變數和 <code>If</code>，可謂是相當方便。</p><p>打開 <code>Pallet</code> 的設定頁面後，在 <code>請選取放置模式</code> 的地方會有四種模式選，這四種放置的方式就如同它圖示展示般，很是直觀，有興趣的同學可以在自由練習時，把四種模式都設定來玩玩看。底下的 <code>請教導三點以創造棧板放置組態</code> 則可依照上方 <code>請選取放置模式</code> 圖標中的 ①、②、③ 相對位置對照設置即可。例如以 <code>請選取放置模式</code> 的第一種模式而言，對應板子就要設定<strong>右上角</strong> → <strong>左上角</strong> → <strong>左下角</strong>，直接把手臂拉過去對三個點後，再按下對應的 <code>取得第一點</code>、<code>取得第二點</code>、<code>取得第三點</code> 以設置點位。</p><p>再更底下的 <code>行數與列數</code>，以放麻將的板子的情況來說，就要在 <code>≡</code> 輸入 <code>3</code>、<code>⦀</code> 輸入 <code>2</code>。</p><p>剩下的設定都不用動它，直接點擊 <code>確定</code> 後關閉視窗，即完成 <code>Pallet</code> 節點的設定。</p><h2 id="manual-decision" tabindex="-1">Manual-Decision <a class="header-anchor" href="#manual-decision" aria-label="Permalink to &quot;Manual-Decision&quot;">​</a></h2><p>簡稱 <code>M-Decision</code>，是流程編輯軟體中，少數可以達成<strong>人機交互</strong>的功能，也就是讓別人在跑你專案時，有辦法透過選擇來控制手臂的行為。</p><p>在 <code>M-Decision</code> 節點底下，還會出現數個子節點，表示不同選擇，不過，所有的設定都直接點進主要 <code>M-Decision</code> 的鉛筆圖示即可。<code>標題</code> 和 <code>內文</code> 的設定就如同 <code>Display</code>，重點是底下的 <code>判斷設定條件</code> 要設定好，那裡就相當於「選項」的部分，你可以點擊 <img src="'+e+'" alt="新增選項圖示" style="width:25px;display:inline;vertical-align:middle;margin:0 5px;"> 來加入更多選擇，並用各選擇的鉛筆圖示來設定它們，其實只要設定好 <code>標題</code> 即可，它會成為選項顯示出來的文字。</p><p>你可以執行寫好的專案以測試 <code>M-Decision</code>，選擇選項時，可以用滑鼠直接點擊，或者控制器上 <code>+</code> 和 <code>-</code> 來調整選項，並用 <code>PLAY</code> 選擇。</p><h2 id="set-坐標參數化" tabindex="-1">Set（坐標參數化） <a class="header-anchor" href="#set-坐標參數化" aria-label="Permalink to &quot;Set（坐標參數化）&quot;">​</a></h2><p>我們先前已經學過 <code>Set</code> 的兩種應用了，也就是末端模組和變數的控制，現在我們再來看一個和變數十分相似的功能——坐標參數化。從它的名字中，我們大概可以猜到它和變數控制的操作是很像的，只不過現在，這個變數不是我們自己設定的變數，而是坐標的數值。</p><p>為什麼要控制坐標數值？其實這個主要是應用在當你要擺放數個工件在同樣的地方時的情況，因為若夾取物件到達一模一樣的位置，那結果可想而之，它必然會撞機，因此我們可以讓它往上或是往四周移動一小段距離，使兩個工件不會撞到，無論要向哪個方向調整，都要用到坐標參數化的觀念。</p><p>在 <code>Set</code> 的設定頁面中，我們一樣要選擇 <code>變數</code> 的 <code>選擇</code>，並進入到和控制變數一樣的介面，不過，這次我們要開啟左側 <code>參數化</code> 選單。它會依賴於一個點位，也就是我們想要它偏移的那個點，在 <code>選擇</code> 選單中可以設定要參數化的 <code>Point</code>；<code>屬性</code> 的部分不用動它，直接看到下方的 <code>機器人項目</code>，它就是用來控制坐標的，在下拉選單中，我們可以看到從 <code>float/Value[0]</code> 到 <code>float/Value[5]</code>，分別對應 x、y、z、Rx、Ry、Rz 六個軸，例如我們想要往上疊，就選擇 <code>float/Value[2]</code>，再點擊 <code>插入</code>。</p><p>後面的操作就和變數控制一樣了，格子中分別填入 <code>float/Value[2]</code>、<code>+=</code>、<code>20</code>（單位：mm），如此，我們就設定好了坐標的參數化。</p>',42)])])}const f=d(i,[["render",l]]);export{u as __pageData,f as default};
